{
  "action": "submit_and_backtest",
  "strategy": {
    "name": "Cross Asset Momentum V9",
    "strategy_code": "import pandas as pd
import numpy as np
from app.strategy.base import BaseStrategy


class CrossAssetMomentumV9(BaseStrategy):
    name = 'Cross Asset Momentum V9'
    multi_asset = True

    def generate_signals(self, data: dict) -> dict:
        rebal_freq = self.params.get('rebal_freq', 21)
        target_vol = self.params.get('target_vol', 0.20)
        vol_lookback = self.params.get('vol_lookback', 63)
        n_risky = self.params.get('n_risky', 2)

        all_syms = list(data.keys())
        dates = data[all_syms[0]].index
        n = len(dates)

        risky_pool = ['SPY', 'QQQ', 'IWM', 'VTI', 'EFA']
        safe_pool = ['TLT', 'GLD', 'AGG']
        risky = [s for s in risky_pool if s in data]
        safe = [s for s in safe_pool if s in data]

        sig = {s: np.zeros(n, dtype=int) for s in all_syms}
        sz = {s: np.zeros(n, dtype=float) for s in all_syms}
        holdings = {}
        min_bar = 252 + 5

        def mom_12_1(s, i):
            px = data[s]['close'].values
            if i < 252:
                return None
            p1m = float(px[i - 21])
            p12m = float(px[i - 252])
            if min(p1m, p12m) <= 0:
                return None
            return p1m / p12m - 1

        def above_sma200(s, i):
            px = data[s]['close'].values
            if i < 200:
                return False
            sma = float(np.mean(px[i - 200:i]))
            return float(px[i]) > sma

        def get_vol(s, i):
            if i < vol_lookback + 1:
                return 0.15
            px = data[s]['close'].values
            rets = np.diff(np.log(px[i - vol_lookback:i + 1]))
            return max(float(np.std(rets)) * np.sqrt(252), 0.05)

        for i in range(min_bar, n):
            if i % rebal_freq != 0:
                for s, w in holdings.items():
                    if s in data:
                        sig[s][i] = 1
                        sz[s][i] = w
                continue

            # Risky: must have positive 12-1 momentum AND be above 200-day SMA
            risky_qual = {}
            for s in risky:
                sc = mom_12_1(s, i)
                if sc is not None and sc > 0 and above_sma200(s, i):
                    risky_qual[s] = sc

            # Safe: rank by momentum
            safe_scores = {}
            for s in safe:
                sc = mom_12_1(s, i)
                if sc is not None:
                    safe_scores[s] = sc

            best_safe = (
                max(safe_scores.keys(), key=lambda s: safe_scores[s])
                if safe_scores else (safe[0] if safe else None)
            )

            top_risky = sorted(
                risky_qual.keys(), key=lambda s: risky_qual[s], reverse=True
            )[:n_risky]
            n_r = len(top_risky)

            target_weights = {}
            if n_r == 0:
                # Fully defensive
                if best_safe:
                    target_weights[best_safe] = 0.95
            elif n_r == 1:
                # One risky + safe hedge
                target_weights[top_risky[0]] = 0.60
                if best_safe:
                    target_weights[best_safe] = 0.35
            else:
                # Two risky — fully invested
                per = 0.95 / n_r
                for s in top_risky:
                    target_weights[s] = per

            # Vol-scale: only reduce if asset vol exceeds target (never cap upside)
            holdings = {}
            for s, w in target_weights.items():
                v = get_vol(s, i)
                scale = min(1.0, target_vol / v)
                holdings[s] = w * scale

            total_h = sum(holdings.values())
            if total_h > 0.95:
                holdings = {s: w * 0.95 / total_h for s, w in holdings.items()}

            for s in all_syms:
                sig[s][i] = 0
                sz[s][i] = 0.0
            for s, w in holdings.items():
                if s in data:
                    sig[s][i] = 1
                    sz[s][i] = float(w)

        return {
            s: pd.DataFrame({'signal': sig[s], 'size_pct': sz[s]}, index=dates)
            for s in all_syms
        }
